package paa_test

import (
	"bytes"
	"os"
	"testing"

	"github.com/jmhobbs/go-paa"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func Test_Decode_DX1_TestFile(t *testing.T) {
	// This is a test file generated by ImageToPAA
	f, err := os.Open("testdata/test-pattern.paa")
	if err != nil {
		t.Fatal(err)
	}
	defer f.Close()

	img, err := paa.Decode(f)
	require.NoError(t, err)
	require.NotNil(t, img)

	require.NotNil(t, img.AVGC, "AVGC should not be nil")
	assert.Equal(t, uint8(0xb6), img.AVGC.Red)
	assert.Equal(t, uint8(0xaa), img.AVGC.Green)
	assert.Equal(t, uint8(0xa9), img.AVGC.Blue)
	assert.Equal(t, uint8(0xff), img.AVGC.Alpha)

	require.NotNil(t, img.MAXC, "MAXC should not be nil")
	assert.Equal(t, [4]uint8{0xff, 0xff, 0xff, 0xff}, img.MAXC.Data)

	require.NotNil(t, img.OFFS, "OFFS should not be nil")
	assert.Equal(
		t,
		[16]uint32{
			0x70,
			0x02f6,
			0x0472,
			0x1479,
			0x1880,
			0x1987,
			0x19ce,
			// everything else is 0x00
		},
		img.OFFS.Offsets,
	)
}

func Test_Decode_DX1_AVGC(t *testing.T) {
	src := bytes.NewReader([]byte{
		0x01, 0xff, // DX1
		0x47, 0x47, 0x41, 0x54, // TAGG
		0x43, 0x47, 0x56, 0x41, // AVGC
		0x04, 0x00, 0x00, 0x00, // Length: 4
		0xb6,                   // Red
		0xaa,                   // Green
		0xa9,                   // Blue
		0xff,                   // Alpha
		0x00, 0x00, 0x00, 0x00, // junk data to mark end of TAGG
	})

	img, err := paa.Decode(src)
	require.NoError(t, err)
	require.NotNil(t, img.AVGC)
	assert.Equal(t, uint8(0xb6), img.AVGC.Red)
	assert.Equal(t, uint8(0xaa), img.AVGC.Green)
	assert.Equal(t, uint8(0xa9), img.AVGC.Blue)
	assert.Equal(t, uint8(0xff), img.AVGC.Alpha)
}

func Test_Decode_DX1_MAXC(t *testing.T) {
	src := bytes.NewReader([]byte{
		0x01, 0xff, // DX1
		0x47, 0x47, 0x41, 0x54, // TAGG
		0x43, 0x58, 0x41, 0x4d, // MAXC
		0x04, 0x00, 0x00, 0x00, // Length: 4
		0xff, 0xff, 0xff, 0xff, // Data
		0x00, 0x00, 0x00, 0x00, // junk data to mark end of TAGG
	})

	img, err := paa.Decode(src)
	require.NoError(t, err)
	require.NotNil(t, img.MAXC)
	assert.Equal(t, [4]uint8{0xff, 0xff, 0xff, 0xff}, img.MAXC.Data)
}

func Test_Decode_DX1_OFFS(t *testing.T) {
	src := bytes.NewReader([]byte{
		0x01, 0xff, // DX1
		0x47, 0x47, 0x41, 0x54, // TAGG
		0x53, 0x46, 0x46, 0x4f, // OFFS
		0x40, 0x00, 0x00, 0x00, // Length: 64 (16*4)
		0x01, 0x00, 0x00, 0x00, // Offsets[0]
		0x02, 0x00, 0x00, 0x00, // Offsets[1]
		0x03, 0x00, 0x00, 0x00, // Offsets[2]
		0x04, 0x00, 0x00, 0x00, // Offsets[3]
		0x05, 0x00, 0x00, 0x00, // Offsets[4]
		0x06, 0x00, 0x00, 0x00, // Offsets[5]
		0x07, 0x00, 0x00, 0x00, // Offsets[6]
		0x08, 0x00, 0x00, 0x00, // Offsets[7]
		0x09, 0x00, 0x00, 0x00, // Offsets[8]
		0x0a, 0x00, 0x00, 0x00, // Offsets[9]
		0x0b, 0x00, 0x00, 0x00, // Offsets[10]
		0x0c, 0x00, 0x00, 0x00, // Offsets[11]
		0x0d, 0x00, 0x00, 0x00, // Offsets[12]
		0x0e, 0x00, 0x00, 0x00, // Offsets[13]
		0x0f, 0x00, 0x00, 0x00, // Offsets[14]
		0x10, 0x00, 0x00, 0x00, // Offsets[15]
		0x00, 0x00, 0x00, 0x00, // junk data to mark end of TAGG
	})

	img, err := paa.Decode(src)
	require.NoError(t, err)
	require.NotNil(t, img.OFFS)
	for i := range 16 {
		assert.Equal(t, uint32(i+1), img.OFFS.Offsets[i])
	}
}
